#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long bags = (X * Y) / 100;
        printf("%lld\n", bags);
    }
    return 0;
}

